string deletePatern = "";
string choice = " ";
Stack<Statistic> history = new Stack<Statistic>();

while (choice != "0")
{
    Console.WriteLine("1. Провести анализ\n2. Ввести новый текст\n3. Вывести статистику по прошлому тексту\n4. Ввести свой патерн\n0. Выход");
    choice = Console.ReadLine();

    
    switch (choice)
    {
        case "1":
            printStats(Analysis(text, deletePatern));
            break;
        case "2":
            history.Push(Analysis(text, deletePatern));
            text = SetNewText();
            break;
        case "3":
            printStats(history.Peek());
            break;
        case "4":
            deletePatern = SetDeletePatern();
            break;
        case "0":
            break;
    }
}
void printStats(Statistic input) {
    Console.WriteLine($"---------------------------------\nСтатистика:\nКоличество предложений: {input.countOfSentences}\nКоличество слов: {input.countOfWords}\nКоличество гласных: {input.countOfVowels}\nКоличество согласных: {input.countOfСonsonants}\nСамое длинное слово: {input.longestWord}\nСамое короткое слово: {input.shortestWord}\nДОПОЛНИТЕЛЬНО. Кол-во слов без союзов и чисел: {input.countOfWordsWithoutNumsUnions}\n---------------------------------");

    Console.WriteLine("\nЧастота встречаемости различных букв в тексте:\n----------------------------------------------");
    foreach (var (key, val) in input.frequency)
    {
        Console.WriteLine($"Буква {key}: {val}");
    }
    Console.WriteLine("----------------------------------------------");
}
Statistic Analysis(string text, string userPatern) {

    SortedDictionary<char, int> frequency = new SortedDictionary<char, int>();

    int countOfWords = 0;
    int countOfSentences = 0;
    int countOfVowels = 0;
    int countOfСonsonants = 0;

    string namePatern = @". bb. ";
    string vowelPatern = "аеёиоуыэюя";
    string charsPatern = ".!?";
    string patern = ",\n\r\":-";

    string addPaternUnions = "ианодазатоилилибопотомучтотаккакчтобыкогдапокаеслибыбудтохотя";
    //string addPaternNums = "0123456789xvi";

    int countOfWordsWithoutNumsUnions = 0;

    string[] textlst = text.Split(separator: " ");
    string shortestWord = textlst[0];
    string longestWord = textlst[0];

    string tempSectence = ". ";
    foreach (string word in textlst) {

        countOfWordsWithoutNumsUnions++; // подсчет слов без союзов и чисел
        countOfWords++; // подсчет слов

        if (addPaternUnions.Contains(word)) {
            countOfWordsWithoutNumsUnions--;
        }

        if (word == "-" || word == "\"") {
            countOfWords--;
            countOfWordsWithoutNumsUnions--;
            continue;
        }
        if (shortestWord.Length > word.Length) // выявление кратчайшего слова
        {
            shortestWord = word;
        }

        if (longestWord.Length < word.Length) // выявление длинейшего слова
        {
            longestWord = word;
        }

        string lowerWord = word.ToLower();

        for (int i = 0; i < word.Length; i++) {

            //if (addPaternNums.Contains(word[i]))
            //{
            //    Console.WriteLine(word[i]);
            //    Console.WriteLine("Напоросля на число!");
            //    //countOfWordsWithoutNumsUnions--;
            //    continue;
            //}

            if (userPatern != "") {
                if (userPatern.Contains(word[i])) { continue; }
            }

            tempSectence += "b";

            if (vowelPatern.Contains(lowerWord[i]))
            {
                countOfVowels++; // подсчет глассных

                if (frequency.ContainsKey(lowerWord[i]))
                {
                    frequency[lowerWord[i]]++;
                }
                else
                {
                    frequency.Add(lowerWord[i], 1);
                }
            }
            else if (charsPatern.Contains(lowerWord[i]))
            {
                countOfSentences++; // подсчет предложений
                tempSectence += ". ";

            }
            else if (patern.Contains(lowerWord[i]) == false)
            {
                countOfСonsonants++; // подсчет соглассных
                if (frequency.ContainsKey(lowerWord[i]))
                {
                    frequency[lowerWord[i]]++;
                }
                else
                {
                    frequency.Add(lowerWord[i], 1);
                }
            }
        }

    }
    if (tempSectence.Contains(namePatern)) { countOfSentences -= 2; }

    Statistic stats = new Statistic(text,countOfSentences,countOfWords,longestWord,shortestWord, frequency, countOfСonsonants, countOfVowels, countOfWordsWithoutNumsUnions);
    return stats;
}
string SetNewText() {

    Console.WriteLine("Введите текст для анализа");
    string text = Console.ReadLine();
    
    while (true)
    {
        int count = 0;
        string[] textlst = text.Split(separator: " ");

        foreach (string word in textlst)
        {
            count++;

            if (count == 100)
            {
                return text;
            }
        }
        Console.WriteLine("Введите новый текст (кол-во слов в котором превышает 100)");
        text = Console.ReadLine();
    }
}
string SetDeletePatern() {
    Console.WriteLine("Вписывайте буквы которые хотите не учитывать при анализе (если хотите закончить, введите 0):");
    string input = Console.ReadLine();
    string patern = "";

    while (input != "0") {
        patern += input;

        input = Console.ReadLine();
    }

    return patern;
}
class Statistic {
    public string text;
    public int countOfSentences;
    public int countOfWords;
    public string longestWord;
    public string shortestWord;

    public int countOfVowels;
    public int countOfСonsonants;

    public int countOfWordsWithoutNumsUnions;

    public SortedDictionary<char, int> frequency;

    public Statistic(string text, int countOfSentences, int countOfWords, string longestWord, string shortestWord, SortedDictionary<char, int> f, int countOfСonsonants, int countOfVowels, int countOfWordsWithoutNumsUnions)
    {
        this.text = text;
        this.countOfSentences = countOfSentences;
        this.countOfWords = countOfWords;
        this.longestWord = longestWord;
        this.shortestWord = shortestWord;
        this.frequency = f;
        
        this.countOfСonsonants = countOfСonsonants;
        this.countOfVowels = countOfVowels;

        this.countOfWordsWithoutNumsUnions = countOfWordsWithoutNumsUnions;
    }
}